// =============================================================
// API 키 인증 및 입력 값 검증
// X-API-Key 헤더를 확인하여 인가된 요청만 처리
// =============================================================

const headers = $input.first().json.headers || {};
const body    = $input.first().json.body || {};

// 환경 변수에서 API 키 로드
let expectedApiKey;
try { expectedApiKey = $env.API_SECRET_KEY; } catch(e) {}
expectedApiKey = expectedApiKey || 'n8n-ollama-api-key-2024';
const providedApiKey = headers['x-api-key'] || headers['X-API-Key'] || '';

// 인증 실패 처리
if (providedApiKey !== expectedApiKey) {
  throw new Error('AUTH_FAILED: 유효하지 않은 API 키입니다. X-API-Key 헤더를 확인하세요.');
}

// 필수 입력 값 검증
const userMessage = (body.message || '').trim();
const sessionId   = (body.session_id || `session_${Date.now()}`).trim();

if (!userMessage) {
  throw new Error('VALIDATION_ERROR: message 필드는 필수입니다.');
}

if (userMessage.length > 4000) {
  throw new Error('VALIDATION_ERROR: 메시지는 4000자를 초과할 수 없습니다.');
}

// 요청 타임스탬프 기록 (응답 시간 측정용)
const requestStartTime = Date.now();

return {
  userMessage,
  sessionId,
  requestStartTime,
  requestId: `req_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`
};

// =============================================================
// 대화 기록 파싱 및 Ollama 프롬프트 포맷팅
// Redis에서 가져온 JSON 기록을 메시지 배열로 변환
// =============================================================

const authData    = $('인증 및 입력 검증').first().json;
const redisResult = $input.first().json;

// Redis에서 가져온 대화 기록 파싱 (없으면 빈 배열)
let conversationHistory = [];
try {
  const raw = redisResult.value || redisResult || null;
  if (raw && typeof raw === 'string') {
    conversationHistory = JSON.parse(raw);
  } else if (Array.isArray(raw)) {
    conversationHistory = raw;
  }
} catch (e) {
  // 파싱 실패 시 새 대화 시작
  conversationHistory = [];
}

// 최대 기록 수 제한 (환경 변수 기준)
let _maxHistLen; try { _maxHistLen = $env.MAX_HISTORY_LENGTH; } catch(e) {}
const maxHistory = parseInt(_maxHistLen || '20', 10);
if (conversationHistory.length > maxHistory) {
  // 최신 기록만 유지 (시스템 메시지 제외)
  conversationHistory = conversationHistory.slice(-maxHistory);
}

// 시스템 프롬프트 정의
const systemPrompt = `당신은 친절하고 전문적인 AI 어시스턴트입니다.
다음 지침을 따라 응답하세요:
1. 반드시 한국어로만 응답하세요. 영어를 사용하지 마세요.
2. 명확하고 구조적인 답변을 제공하세요.
3. 이전 대화 맥락을 고려하여 일관성 있는 응답을 유지하세요.
4. 불확실한 정보는 명시적으로 표현하세요.`;

// Ollama API 형식의 메시지 배열 구성
const messages = [
  { role: 'system', content: systemPrompt },
  ...conversationHistory,
  { role: 'user', content: authData.userMessage }
];

const ollamaBody = {
  model: 'exaone3.5:2.4b',
  messages,
  stream: false,
  options: { temperature: 0.7, top_p: 0.9, num_predict: 1024 }
};

return {
  ...authData,
  messages,
  conversationHistory,
  historyLength: conversationHistory.length,
  ollamaBody
};

// =============================================================
// Ollama 응답 파싱 및 대화 기록 업데이트 준비
// 새 메시지를 기록에 추가하고 Redis 저장 형식으로 변환
// =============================================================

const ollamaResponse = $input.first().json;
const promptData     = $('프롬프트 포맷팅').first().json;

// Ollama 응답에서 메시지 내용 추출
const aiMessage = ollamaResponse?.message?.content || ollamaResponse?.response || '응답을 생성하는 데 실패했습니다.';
const modelUsed = ollamaResponse?.model || 'exaone3.5:2.4b';

// 응답 시간 계산 (밀리초)
const responseTime = Date.now() - promptData.requestStartTime;

// 대화 기록에 새 교환 추가
const updatedHistory = [
  ...promptData.conversationHistory,
  { role: 'user',      content: promptData.userMessage },
  { role: 'assistant', content: aiMessage }
];

// 최대 기록 수 적용
let _maxH; try { _maxH = $env.MAX_HISTORY_LENGTH; } catch(e) {}
const maxHistory = parseInt(_maxH || '20', 10);
const trimmedHistory = updatedHistory.length > maxHistory
  ? updatedHistory.slice(-maxHistory)
  : updatedHistory;

return {
  sessionId:       promptData.sessionId,
  requestId:       promptData.requestId,
  userMessage:     promptData.userMessage,
  aiMessage,
  modelUsed,
  responseTime,
  updatedHistory:  JSON.stringify(trimmedHistory),
  requestStartTime: promptData.requestStartTime
};

// =============================================================
// 최종 응답 포맷팅
// 클라이언트에게 반환할 JSON 구조 생성
// =============================================================

const parsedData = $('응답 파싱').first().json;

// 성공 응답 구성
const finalResponse = {
  success:   true,
  requestId: parsedData.requestId,
  sessionId: parsedData.sessionId,
  data: {
    message:   parsedData.aiMessage,
    timestamp: new Date().toISOString()
  },
  metadata: {
    model:        parsedData.modelUsed,
    responseTime: `${parsedData.responseTime}ms`,
    historySize:  JSON.parse(parsedData.updatedHistory).length
  }
};

return { response: JSON.stringify(finalResponse) };

// =============================================================
// 에러 처리 노드
// 인증 실패, 검증 오류, LLM 오류 등을 구분하여 처리
// =============================================================

const error = $input.first().json.error || {};
const errorMessage = error.message || '알 수 없는 오류가 발생했습니다.';

// 에러 유형 분류
let statusCode = 500;
let errorCode  = 'INTERNAL_ERROR';

if (errorMessage.startsWith('AUTH_FAILED')) {
  statusCode = 401;
  errorCode  = 'UNAUTHORIZED';
} else if (errorMessage.startsWith('VALIDATION_ERROR')) {
  statusCode = 400;
  errorCode  = 'BAD_REQUEST';
} else if (errorMessage.includes('ECONNREFUSED') || errorMessage.includes('timeout')) {
  statusCode = 503;
  errorCode  = 'SERVICE_UNAVAILABLE';
}

return {
  errorResponse: JSON.stringify({
    success:   false,
    error:     errorCode,
    message:   errorMessage.replace(/^[A-Z_]+: /, ''),
    timestamp: new Date().toISOString()
  }),
  statusCode
};
